// MARK: - Errors

enum LaunchAtLoginError: Error, CustomStringConvertible {
    /// Triggered when the running executable is not wrapped in a `.app` bundle —
    /// e.g. invoked through `swift run` during development. Registering in that
    /// case appends a new legacy login-item entry on every call (since
    /// `SMAppService.mainApp` cannot resolve a stable bundle URL), which is what
    /// caused multiple instances to launch at login.
    case notRunningFromAppBundle(executablePath: String)

    var description: String {
        switch self {
        case let .notRunningFromAppBundle(path):
            "Launch-at-login is only supported when running from a packaged .app bundle (current executable: \(path))."
        }
    }

    var localizedDescription: String { description }
}

// MARK: - Production implementation

@MainActor
final class LaunchAtLoginService: LaunchAtLoginManaging {
    static let shared = LaunchAtLoginService()

    var isEnabled: Bool {
        // `.requiresApproval` means the entry is registered but the user hasn't
        // confirmed it in System Settings yet — treat it as enabled so we don't
        // re-register and stack a duplicate entry.
        switch SMAppService.mainApp.status {
        case .enabled, .requiresApproval: true
        default: false
        }
    }

    func setEnabled(_ enabled: Bool) throws {
        // Idempotence guard — `register()` and `unregister()` are not no-ops when
        // already in the target state; in particular, repeated `register()` calls
        // from a non-bundled binary (dev `swift run`) accumulate stale legacy
        // login-item entries that all fire on next login.
        if enabled == isEnabled { return }

        if enabled {
            try ensureRunningFromAppBundle()
            try SMAppService.mainApp.register()
        } else {
            try SMAppService.mainApp.unregister()
        }
    }

    private func ensureRunningFromAppBundle() throws {
        let bundlePath = Bundle.main.bundlePath
        if !bundlePath.hasSuffix(".app") {
            throw LaunchAtLoginError.notRunningFromAppBundle(executablePath: bundlePath)
        }
    }
}

